var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"로널드 박사님! 로널드 박사님!","JPN":"ロナルド博士！　ロナルド博士！","ENG":"Dr. Ronald! Dr. Ronald!","TWN":"博士！羅那魯多·李博士！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"틀렸어! 고치 관측소와 연결이 안 돼! 무슨 일이 생긴 건가?","JPN":"ダメだ！　繭観測所と繋がらない！　何かあったのかしら？","ENG":"Ugh! It's not connecting us to the cocoon observatory! What's going on over there?","TWN":"不行！無法接通繭觀測站！發生什麼事了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"얼레? 근데 뭔가 침식체 녀석들의 움직임이 이상한데?","JPN":"あれ？　でも何だか侵食体の連中の動きがおかしいわね？","ENG":"Huh? But the movement of those C.O.s are kinda weird.","TWN":"喔？這裡的侵蝕體行為有些奇怪？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"고치가 있는 곳으로부터 침식체가 무리를 지어 어디론가 이동하고 있어.","JPN":"繭のある場所から侵食体が群れを成してどこかに移動してる。","ENG":"The C.O.s are moving away in hordes from where the cocoon is.","TWN":"他們正從繭所在的地方，成群結隊地往某個地方移動。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"설마 카운터가 없는 틈을 타서 거점 기지를 습격했다고?","JPN":"まさかカウンターの不在をついて拠点基地を襲ったというの？","ENG":"Did they ambush the base while no Counter was present?","TWN":"難道他們想趁著制裁者不在，襲擊據點基地?"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"침식체가 양동작전 같은 걸 펼칠 수 있을 리가…….","JPN":"侵食体に陽動作戦なんて使えるわけが……","ENG":"There's no way C.O.s can pull off a feint operation...","TWN":"侵蝕體還會聲東擊西……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전 대원, 현장에서 관측된 개체를 <color=#ffd34c>아종 네피림</color>으로 간주!","JPN":"全隊員、現場で観測された個体を<color=#ffd34c>亜種ネフィリム</color>と見なします！","ENG":"All units, the creature observed on the field will be considered a <color=#ffd34c>Nephil subspecies</color>!","TWN":"全體隊員，現場觀測到的個體歸類為<color=#ffd34c>亞種諾菲力</color>！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"현 시간부로, 긴급 작전 태세에 돌입합니다!","JPN":"現時刻より、緊急作戦体制に突入します！","ENG":"From this point on, we are on emergency alert!","TWN":"即刻起，進入緊急作戰狀態！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사이버캣, 지금 즉시 공간 도약을 준비하세요! 본부로 돌아가겠습니다!","JPN":"サイバーキャット、今すぐに空間跳躍の準備をしてください！　本部に帰還します！","ENG":"Cyber Cat, prepare for an immediate space jump! We head back to HQ!","TWN":"賽博貓，現在立刻準備進行跳躍！返回總部！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"알겠어! 공간 도약 시퀸스 준비!","JPN":"わかったわ！　空間跳躍シークエンス準備！","ENG":"Roger! Preparing the space jump sequence!","TWN":"明白！空間跳躍程式準備！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"공간 도약 스타트!","JPN":"空間跳躍、開始！","ENG":"Initiating the space jump!","TWN":"空間跳躍啟動！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Kgh!","TWN":"呃？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"윽!! 무슨 일이에요, 사이버캣! 상황 보고하세요!","JPN":"くっ！！　何が起きたんですか、サイバーキャット！　状況報告を！","ENG":"Ngh!! Report, Cyber Cat! What just happened?!","TWN":"怎麼了，賽博貓！報告情況！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"나도 몰라! 공간 도약은 정상적으로 진행 중, 이미 초공간에 돌입했어!","JPN":"アタシにもよくわからないわ！　空間跳躍は正常に進行中、すでに超空間に突入してる！","ENG":"I dunno! The space jump is operating normally and we've already entered hyperspace!","TWN":"我也不知道！空間跳躍正常進行中，已進入超空間！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L26_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"아마도 이런 충격이면, 공간 도약 직전에 무언가와 충돌한 것 같은데?","JPN":"たぶん今の衝撃は空間跳躍の直前に何かと衝突したんじゃない？","ENG":"With an impact like this, we must have collided with something right before the space jump.","TWN":"不過這種衝擊，也許是跳躍之前與某種東西發生了碰撞？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"서, 설마?","JPN":"ま、まさか？","ENG":"C-could it be...?","TWN":"難，難道是？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사이버캣! 선체의 외부 카메라를 연결해주세요!","JPN":"サイバーキャット！　船体の外部カメラに繋げてください！","ENG":"Cyber Cat! Connect me to the exterior camera of the ship!","TWN":"賽博貓！連接船身外部鏡頭！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"저 녀석, 초공간에 돌입한 함선의 외부 장갑에 손톱을 박아 넣고 견디고 있어?","JPN":"あいつ、超空間に突入した艦船外部の装甲の隙間に爪を刺し込んで耐えてる？","ENG":"That thing... It jammed its hand into the ship's plating and is still holding on even though the ship's already in hyperspace!","TWN":"那個東西把手扣在艦船外裝甲上，緊緊跟著艦船？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"저게 말이 돼? 대체 어떻게 돼먹은 괴물이야, 저거!","JPN":"そんなのあり得ないわ！　どんな化け物なのよ、あれ！","ENG":"How's that even possible? What kind of monster is that thing?!","TWN":"怎麼可能？到底是個什麼怪物！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그야 당연하겠죠, 저건 세상을 끝장낼 뻔한 괴물이었으니까요!","JPN":"驚くことじゃないですよ、なんせ世界を滅ぼしかけた化け物なんですから！","ENG":"It's only natural. That monster almost ended the world!","TWN":"那可是差點毀滅全世界的怪物，不是理所當然的嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그래도 뭔가 이상한데요?","JPN":"でも何だか妙じゃないですか？","ENG":"Still, something feels off.","TWN":"不過有些奇怪……？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무래도 저 네피림, 우리가 도약하는 순간을 노리고 덮친 것 같은데요?","JPN":"あのネフィリム、私たちが跳躍する瞬間を狙って襲ってきた感じでしたよ？","ENG":"My suspicion is that the Nephil intentionally attacked us right when we were about to jump.","TWN":"這隻諾菲力好像是瞄準我們跳躍的瞬間撲過來的？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네피림에게 지성이 있을 리가 없는데 말이죠.","JPN":"ネフィリムに知性なんてあるわけないのに。","ENG":"But there's no way a Nephil has any intelligence.","TWN":"按理說諾菲力不應該會有智力吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이대로라면 저 네피림을 끌고 본부까지 공간 도약할지도 모릅니다!","JPN":"このままでは、あのネフィリムと一緒に本部まで空間跳躍をしてしまいます！","ENG":"At this rate, we'll be dragging the Nephil right to HQ with our space jump!","TWN":"這樣下去，可能會帶著這隻諾菲力一起跳躍到總部！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사이버캣! 당장 공간 도약을 중지하세요!!","JPN":"サイバーキャット！　今すぐに空間跳躍を中止してください！！","ENG":"Cyber Cat! Abort the space jump right now!","TWN":"賽博貓！馬上停止空間跳躍！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"먼저 아종 네피림을 선체에서 떨어트려야 해요!!","JPN":"まずはあの亜種ネフィリムを船体から振り落とすんです！！","ENG":"We need to shake off that Nephil subspecies from our ship first!!","TWN":"需要先把亞種諾菲力從船身打落下去！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"이미 하고 있다고!!","JPN":"もうやってるわよ！！","ENG":"I'm already on it!!","TWN":"我已經在做了！！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"좌표 변경! 비상 시퀸스 돌입! 초공간으로부터 이탈한다!","JPN":"座標変更！　非常シークエンスに突入！　超空間から離脱する！","ENG":"Changing coordinates! Entering emergency sequence! Escaping hyperspace!","TWN":"座標變更！緊急程式開啟！從超空間脫離！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"3…… 2…… 1……!","JPN":"3……2……1……！","ENG":"In 3... 2... 1...!","TWN":"3……2……1……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"꽉 잡아!!","JPN":"しっかり掴まっててよ！！","ENG":"Hold on tight!","TWN":"抓緊了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"크윽!! 어떻게든 초공간 이탈은 성공했어!","JPN":"くっ！！　なんとか超空間からは脱出できたわ！","ENG":"Kgh!! We made it out of hyperspace!","TWN":"咳呃！！超空間脫離成功！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"무리하게 급선회시킨 거라서 함선 엔진 수명이 5년은 줄었겠지만.","JPN":"無理に急旋回したから、艦船のエンジンの寿命が5年は縮まったけどね。","ENG":"But the abrupt turn might have reduced the engine's lifespan by about 5 years.","TWN":"只不過因為勉強急轉彎，艦船引擎壽命應該減少了5年。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"지금 엔진 같은 걸 걱정하고 있을 때가 아닌 것 같은데요?","JPN":"今はエンジンの心配をしている場合じゃないと思いますよ？","ENG":"I don't think we should be worrying about the engine right now, don't you think?","TWN":"現在好像不是擔心引擎的時候吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"당장 저걸 어떻게 하지 않으면, 당장 우리 목숨이 어떻게 될지 모른다고요.","JPN":"あれをなんとかしないと、ここでみんな死んじゃうかもしれませんからね。","ENG":"If we don't deal with that thing immediately, we'll all be dead meat soon.","TWN":"如果不馬上處理掉那傢伙，沒命的馬上就會是我們了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"가죠, 시영 씨! 망설일 시간 같은 건 없어요!","JPN":"行きましょう、シノンさん！　躊躇っている暇はありません！","ENG":"Let's go, Shiyoung! There's no time to waste!","TWN":"走吧，時雨！沒時間猶豫了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저 괴물을 어떻게 쓰러트릴지는 나중에 결정하도록 해요!","JPN":"あの化け物をどう倒すかを議論するのは、また後にしましょう！","ENG":"We'll decide how to defeat that monster later!","TWN":"該怎麼打倒那個怪物以後再說！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우선, 저 아종 네피림을 선체에서 떨어트리는 것에만 집중하는 겁니다!","JPN":"今は、あの亜種ネフィリムを船体から振り落とすことに集中するんです！","ENG":"Our priority right now is to get the Nephil off the ship!","TWN":"首要任務是將他從船身上擊落！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};